from dataclasses import dataclass, field
from enum import Enum
from typing import Optional


class Score(Enum):
    GREEN = "green"    # criterion satisfied, no caveats
    YELLOW = "yellow"  # partially satisfied, condition required
    RED = "red"        # not satisfied, no known path


class GateOutcome(Enum):
    PASS = "pass"
    HOLD = "hold"
    KILL = "kill"


@dataclass
class Criterion:
    name: str
    description: str
    score: Optional[Score] = None
    evidence_ref: str = ""
    blocking: bool = False  # True => any RED is an automatic Kill
    hold_condition: str = ""  # what must be resolved for YELLOW to become GREEN


@dataclass
class Gate:
    name: str
    criteria: list[Criterion] = field(default_factory=list)

    def evaluate(self) -> tuple[GateOutcome, list[str]]:
        """Return (outcome, [reasons])."""
        reasons: list[str] = []
        reds = [c for c in self.criteria if c.score == Score.RED]
        yellows = [c for c in self.criteria if c.score == Score.YELLOW]

        # Any red on a blocking criterion => Kill
        blocking_reds = [c for c in reds if c.blocking]
        if blocking_reds:
            for c in blocking_reds:
                reasons.append(f"BLOCKING RED: {c.name} — {c.description}")
            return GateOutcome.KILL, reasons

        # Any non-blocking reds => Kill
        if reds:
            for c in reds:
                reasons.append(f"RED: {c.name}")
            return GateOutcome.KILL, reasons

        # Three or more yellows in one gate => Hold
        if len(yellows) >= 3:
            for c in yellows:
                reasons.append(f"HOLD condition: {c.hold_condition}")
            return GateOutcome.HOLD, reasons

        # One or two yellows => Pass with noted conditions
        if yellows:
            for c in yellows:
                reasons.append(f"Condition: {c.hold_condition}")
            return GateOutcome.PASS, reasons

        return GateOutcome.PASS, ["All criteria GREEN"]
